import{_ as a,O as r,H as e,f as i,k as l,i as n}from"./chunks/framework.Pt2pSV98.js";const q=JSON.parse('{"title":"AI 开发知识测验","description":"测试你对 API 编程、Agent 开发、工程实践的掌握程度","frontmatter":{"title":"AI 开发知识测验","description":"测试你对 API 编程、Agent 开发、工程实践的掌握程度","difficulty":"intermediate"},"headers":[],"relativePath":"dev/quiz.md","filePath":"dev/quiz.md"}'),s={name:"dev/quiz.md"};function g(p,t,d,h,u,m){const o=r("DifficultyBadge");return e(),i("div",null,[l(o,{level:"intermediate"}),t[0]||(t[0]=n('<h1 id="ai-开发知识测验" tabindex="-1">AI 开发知识测验 <a class="header-anchor" href="#ai-开发知识测验" aria-label="Permalink to &quot;AI 开发知识测验&quot;">​</a></h1><p>测一测你对 AI 开发核心知识的掌握程度。覆盖 API 编程、Agent 流程和工程实践，共 6 道题。</p><hr><h2 id="一、api-编程" tabindex="-1">一、API 编程 <a class="header-anchor" href="#一、api-编程" aria-label="Permalink to &quot;一、API 编程&quot;">​</a></h2><h3 id="q1-openai-api-中设置-stream-true-的作用是-单选" tabindex="-1">Q1：OpenAI API 中设置 <code>stream=True</code> 的作用是？（单选） <a class="header-anchor" href="#q1-openai-api-中设置-stream-true-的作用是-单选" aria-label="Permalink to &quot;Q1：OpenAI API 中设置 `stream=True` 的作用是？（单选）&quot;">​</a></h3><div class="quiz-options"><ul><li><strong>A.</strong> 提高回答质量</li><li><strong>B.</strong> 以流式方式逐块返回结果，实现打字机效果</li><li><strong>C.</strong> 自动重试失败的请求</li><li><strong>D.</strong> 压缩传输数据量</li></ul></div><details><summary>查看答案</summary><p><strong>正确答案：B</strong></p><p><code>stream=True</code> 启用 SSE（Server-Sent Events）流式传输，模型边生成内容边返回，不必等全部生成完才响应。最直观的体验就是&quot;打字机效果&quot;——用户能逐字看到模型的输出，大幅降低感知等待时间。</p><p>A：stream 不改变模型推理质量。<br> C：重试和 stream 无关，需自行实现重试逻辑。<br> D：SSE 流式传输并不压缩数据量，反而因为逐块传输会有轻微协议开销。</p><p>→ 📖 延伸阅读：<a href="./streaming.html">流式响应</a></p></details><hr><h3 id="q2-tool-calling-函数调用-的正确流程是-单选" tabindex="-1">Q2：Tool Calling（函数调用）的正确流程是？（单选） <a class="header-anchor" href="#q2-tool-calling-函数调用-的正确流程是-单选" aria-label="Permalink to &quot;Q2：Tool Calling（函数调用）的正确流程是？（单选）&quot;">​</a></h3><div class="quiz-options"><ul><li><strong>A.</strong> 模型直接调用函数 → 返回结果</li><li><strong>B.</strong> 定义 Tool → 模型返回 Tool 调用请求 → 执行函数 → 返回结果给模型</li><li><strong>C.</strong> 用户指定调哪个 Tool → 模型执行</li><li><strong>D.</strong> 模型自己写函数代码 → 编译运行</li></ul></div><details><summary>查看答案</summary><p><strong>正确答案：B</strong></p><p>Tool Calling 的完整流程是一个<strong>循环</strong>：</p><ol><li>开发者在请求中<strong>定义 Tool</strong>（名称、描述、参数 Schema）</li><li>模型判断需要调用工具后，<strong>返回一个 Tool Call 请求</strong>（JSON 格式，含函数名和参数）</li><li>开发者在自己的环境中<strong>执行该函数</strong>，获取结果</li><li>将执行结果<strong>追加到对话中</strong>，再次发送给模型</li><li>模型根据工具返回的结果<strong>生成最终回答</strong></li></ol><p>模型本身<strong>不会执行代码</strong>，它只输出调用指令。执行权始终在开发者手中，这也是安全设计的一部分。</p><p>→ 📖 延伸阅读：<a href="./tool-calling.html">Tool Calling</a> · <a href="./tool-definition.html">Tool 定义与实现</a></p></details><hr><h2 id="二、agent-开发" tabindex="-1">二、Agent 开发 <a class="header-anchor" href="#二、agent-开发" aria-label="Permalink to &quot;二、Agent 开发&quot;">​</a></h2><h3 id="q3-agent-的-react-循环中-observation-观察-步骤的作用是什么-单选" tabindex="-1">Q3：Agent 的 ReAct 循环中，Observation（观察）步骤的作用是什么？（单选） <a class="header-anchor" href="#q3-agent-的-react-循环中-observation-观察-步骤的作用是什么-单选" aria-label="Permalink to &quot;Q3：Agent 的 ReAct 循环中，Observation（观察）步骤的作用是什么？（单选）&quot;">​</a></h3><div class="quiz-options"><ul><li><strong>A.</strong> 观察用户的反应</li><li><strong>B.</strong> 观察工具执行的结果，决定下一步做什么</li><li><strong>C.</strong> 观察其他 Agent 的行为</li><li><strong>D.</strong> 观察训练数据的分布</li></ul></div><details><summary>查看答案</summary><p><strong>正确答案：B</strong></p><p>ReAct（Reasoning + Acting）循环是 Agent 的核心运行机制：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Thought（思考）→ Action（行动）→ Observation（观察）→ Thought → …… → Answer</span></span></code></pre></div><p>Observation 步骤接收工具执行后的返回值，作为新一轮 Thought 的输入。Agent 基于这个观察结果判断：</p><ul><li>任务是否完成？如果完成，输出最终答案</li><li>是否需要继续调用工具？如果需要，决定下一步 Action</li><li>结果是否异常？如果异常，调整策略重试</li></ul><p>这就是 Agent 区别于普通 LLM 调用的关键——具备<strong>基于反馈的自适应决策能力</strong>。</p><p>→ 📖 延伸阅读：<a href="./agent-intro.html">Agent 核心概念</a> · <a href="./build-agent.html">构建第一个 Agent</a></p></details><hr><h2 id="三、工程实践" tabindex="-1">三、工程实践 <a class="header-anchor" href="#三、工程实践" aria-label="Permalink to &quot;三、工程实践&quot;">​</a></h2><h3 id="q4-以下哪项是防御-prompt-注入的有效手段-单选" tabindex="-1">Q4：以下哪项是防御 Prompt 注入的有效手段？（单选） <a class="header-anchor" href="#q4-以下哪项是防御-prompt-注入的有效手段-单选" aria-label="Permalink to &quot;Q4：以下哪项是防御 Prompt 注入的有效手段？（单选）&quot;">​</a></h3><div class="quiz-options"><ul><li><strong>A.</strong> 用更贵的模型</li><li><strong>B.</strong> 用定界符包裹用户输入，限制模型行为</li><li><strong>C.</strong> 增加模型的参数量</li><li><strong>D.</strong> 关闭模型的联网功能</li></ul></div><details><summary>查看答案</summary><p><strong>正确答案：B</strong></p><p>Prompt 注入的核心问题是<strong>用户输入和系统指令的边界混淆</strong>。防御的首要策略就是明确区分两者：</p><ul><li><strong>定界符隔离</strong>：用 <code>&quot;&quot;&quot;</code> 或 XML 标签等标记包裹用户输入，让模型识别哪些是&quot;不可信的数据&quot;，哪些是&quot;系统规则&quot;</li><li><strong>分层 Prompt</strong>：System Prompt 声明规则且不可被覆盖，User Prompt 携带实际任务</li><li><strong>输入过滤</strong>：检测并拦截已知注入模式（如&quot;忽略上述指令&quot;等关键词）</li><li><strong>输出校验</strong>：检查模型输出是否企图执行非预期的操作</li></ul><p>A：更贵的模型不会天然免疫注入，反而因为指令跟随能力更强，可能更容易被诱导。<br> C：参数量和安全无关。<br> D：联网功能和注入是两个维度的问题。</p><p>→ 📖 延伸阅读：<a href="./ai-security.html">AI 安全</a></p></details><hr><h3 id="q5-推理模型-如-o1、deepseek-r1-适合所有类型的任务-简单问答也应该用它们。-判断" tabindex="-1">Q5：推理模型（如 o1、DeepSeek-R1）适合所有类型的任务，简单问答也应该用它们。（判断） <a class="header-anchor" href="#q5-推理模型-如-o1、deepseek-r1-适合所有类型的任务-简单问答也应该用它们。-判断" aria-label="Permalink to &quot;Q5：推理模型（如 o1、DeepSeek-R1）适合所有类型的任务，简单问答也应该用它们。（判断）&quot;">​</a></h3><div class="quiz-options"><ul><li><strong>○ 正确</strong></li><li><strong>○ 错误</strong></li></ul></div><details><summary>查看答案</summary><p><strong>错误（False）</strong></p><p>推理模型虽然推理能力更强，但代价也很大：</p><table tabindex="0"><thead><tr><th>维度</th><th>推理模型</th><th>通用模型（如 GPT-4o）</th></tr></thead><tbody><tr><td>延迟</td><td>高（需内部思考链）</td><td>低</td></tr><tr><td>成本</td><td>贵（思考 Token 也计费）</td><td>便宜</td></tr><tr><td>适用场景</td><td>数学证明、复杂逻辑、代码调试</td><td>日常问答、翻译、摘要</td></tr></tbody></table><p><strong>决策原则</strong>：任务需要多步推理 → 用推理模型；任务只需知识检索或简单转换 → 用通用模型。简单问答用推理模型是&quot;杀鸡用牛刀&quot;，既慢又贵，收益极低。</p><p>→ 📖 延伸阅读：<a href="./reasoning-models.html">推理模型使用</a></p></details><hr><h3 id="q6-prompt-caching-可以降低-api-调用成本并减少响应延迟。-判断" tabindex="-1">Q6：Prompt Caching 可以降低 API 调用成本并减少响应延迟。（判断） <a class="header-anchor" href="#q6-prompt-caching-可以降低-api-调用成本并减少响应延迟。-判断" aria-label="Permalink to &quot;Q6：Prompt Caching 可以降低 API 调用成本并减少响应延迟。（判断）&quot;">​</a></h3><div class="quiz-options"><ul><li><strong>○ 正确</strong></li><li><strong>○ 错误</strong></li></ul></div><details><summary>查看答案</summary><p><strong>正确（True）</strong></p><p>Prompt Caching 的工作原理：</p><ul><li>当多次请求<strong>共享相同的前缀内容</strong>时（如固定的 System Prompt、RAG 检索到的文档上下文），服务端缓存在首次计算后的 KV Cache</li><li>后续相同前缀的请求<strong>跳过重复计算</strong>，直接从缓存读取</li></ul><p>带来的收益：</p><ul><li><strong>降低成本</strong>：缓存命中部分按缓存 Token 价格计费，远低于完整推理价格（如 Claude 缓存写入贵 25%，但缓存读取便宜 90%；OpenAI 缓存读取便宜 50%）</li><li><strong>减少延迟</strong>：省去重复的 Prefill 阶段，首字延迟（TTFT）显著下降</li><li><strong>典型场景</strong>：固定 System Prompt 的多轮对话、批量处理相同上下文的请求、RAG 应用中的长文档检索</li></ul><p>→ 📖 延伸阅读：<a href="/ai-knowledge/terms/prompt-caching.html">术语：Prompt Caching</a> · <a href="/ai-knowledge/terms/kv-cache.html">术语：KV Cache</a></p></details><hr><p>→ 🔧 <a href="/ai-knowledge/dev/">返回 AI 开发总览</a></p>',31))])}const A=a(s,[["render",g]]);export{q as __pageData,A as default};
